import React, {
useEffect,
useState
}
from "react";

import {
getHodAnalytics
}
from "../../api/analyticsApi";

function HodAnalytics(){

const [data,setData]=
useState(null);

useEffect(()=>{

loadAnalytics();

},[]);

const loadAnalytics =
async()=>{

try{

const res =
await getHodAnalytics();

setData(res.data);

}

catch(err){

console.log(err);

}

};

return(

<div
style={{
padding:"30px"
}}
>

<h2>
HOD Analytics
</h2>

<hr/>

<h3>

Total Faculty :

{

data?.summary?.totalFaculty || 0

}

</h3>

<br/>

<h3>

Faculty List

</h3>

<table
border="1"
cellPadding="10"
style={{
borderCollapse:"collapse",
width:"100%"
}}
>

<thead>

<tr>

<th>Name</th>

<th>Email</th>

</tr>

</thead>

<tbody>

{

data?.facultyList?.map(

(faculty)=>(

<tr
key={faculty._id}
>

<td>

{faculty.name}

</td>

<td>

{faculty.email}

</td>

</tr>

)

)

}

</tbody>

</table>

</div>

);

}

export default HodAnalytics;
